        return <h4  id="one" style={{background:"cyan",border:"1px solid red"}}>I'm from first class </h4>
    }
}
export class Number2 extends Component{
    render(){
        let style2={
                width:"300px"
            }
        return <h4  id="two" style={{color:"red",border:"1px dashed black"}}>I'm from second class</h4>
    }
}
export class Number3 extends Component{
    render(){
        return <h4  id="three">I'm from third class</h4>
    }
}
export class Number4 extends Component{
    render(){
        return <h4 id="four">I'm from fourth class</h4>
    }
}
